mapper.select:
select id, user_id, balance, frozen, total_earned, total_spent, total_refunded, version, create_time, update_time
from virtual_user_credits
where user_id = #{userId}

mapper.update:
update virtual_user_credits
balance = #{balance}, frozen = #{frozen}, total_earned = #{totalEarned}, total_spent = #{totalSpent}, total_refunded = #{totalRefunded}, version = version + 1, update_time = sysdate()
where user_id = #{userId} and version = #{version}

update virtual_user_credits
set balance = balance - #{amount},
    frozen = frozen + #{amount},
    version = version + 1,
    update_time = sysdate()
where user_id = #{userId}
  and version = #{version}
  and balance >= #{amount}

update virtual_user_credits
set frozen = frozen - #{amount},
    total_spent = total_spent + #{amount},
    version = version + 1,
    update_time = sysdate()
where user_id = #{userId}
  and version = #{version}
  and frozen >= #{amount}

update virtual_user_credits
set frozen = frozen - #{amount},
    balance = balance + #{amount},
    total_refunded = total_refunded + #{amount},
    version = version + 1,
    update_time = sysdate()
where user_id = #{userId}
  and version = #{version}
  and frozen >= #{amount}
